import scala.xml.XML
import scala.xml.Node

class ConfigurationService {
  def parseConfiguration(xmlString: String): Node = {
    XML.loadString(xmlString)
  }
  
  def extractSettings(xmlString: String): Map[String, String] = {
    val xml = parseConfiguration(xmlString)
    extractSettingsFromNode(xml)
  }
  
  private def extractSettingsFromNode(node: Node): Map[String, String] = {
    node.child.collect {
      case elem if elem.label == "setting" =>
        val name = elem.attribute("name").map(_.text).getOrElse("")
        val value = elem.text
        name -> value
    }.toMap
  }
  
  def extractEntities(xmlString: String): Map[String, String] = {
    val xml = parseConfiguration(xmlString)
    extractEntitiesFromNode(xml)
  }
  
  private def extractEntitiesFromNode(node: Node): Map[String, String] = {
    node.child.collect {
      case elem if elem.label == "entity" =>
        val name = elem.attribute("name").map(_.text).getOrElse("")
        val value = elem.text
        name -> value
    }.toMap
  }
}